Project.PropertyGroup:
    {{ target_framework }}
    {% for runtime_identifier in runtime_identifiers %}{{ runtime_identifier.canonical_name() }}{% if !loop.last %};{% endif %}{% endfor %}
    {{ package_id }}
    {{ package_version }}
    enable
    latest
    true
    disable
    false
{% if let Some(title) = nuget.title() %}    {{ title }}
{% endif %}{% if let Some(authors) = nuget.authors() %}    {% for author in authors %}{{ author }}{% if !loop.last %};{% endif %}{% endfor %}
{% endif %}{% if let Some(owners) = nuget.owners() %}    {% for owner in owners %}{{ owner }}{% if !loop.last %};{% endif %}{% endfor %}
{% endif %}{% if let Some(description) = nuget.description() %}    {{ description }}
{% endif %}{% if let Some(package_project_url) = nuget.package_project_url() %}    {{ package_project_url }}
{% endif %}{% if let Some(repository_url) = nuget.repository_url() %}    {{ repository_url }}
{% endif %}{% if let Some(repository_type) = nuget.repository_type() %}    {{ repository_type }}
{% endif %}{% if let Some(package_license_expression) = nuget.package_license_expression() %}    {{ package_license_expression }}
{% endif %}{% if let Some(package_icon) = nuget.package_icon() %}    {{ package_icon.package_path() }}
{% endif %}{% if let Some(package_readme_file) = nuget.package_readme_file() %}    {{ package_readme_file.package_path() }}
{% endif %}{% if let Some(package_tags) = nuget.package_tags() %}    {% for tag in package_tags %}{{ tag }}{% if !loop.last %};{% endif %}{% endfor %}
{% endif %}{% if let Some(package_release_notes) = nuget.package_release_notes() %}    {{ package_release_notes }}
{% endif %}{% if let Some(package_require_license_acceptance) = nuget.package_require_license_acceptance() %}    {{ package_require_license_acceptance }}
{% endif %}

